import{_ as d,C as p,o,c as h,a2 as a,b as s,w as t,a as n,E as r,a3 as l}from"./chunks/framework.B72_uj9U.js";const T=JSON.parse('{"title":"Aider — The Edit-Apply-Lint-Test Loop","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/aider/agentic-loop.md","filePath":"research/agents/aider/agentic-loop.md"}'),c={name:"research/agents/aider/agentic-loop.md"};function m(u,e,g,f,b,A){const i=p("Mermaid");return o(),h("div",null,[e[2]||(e[2]=a('<h1 id="aider-—-the-edit-apply-lint-test-loop" tabindex="-1">Aider — The Edit-Apply-Lint-Test Loop <a class="header-anchor" href="#aider-—-the-edit-apply-lint-test-loop" aria-label="Permalink to &quot;Aider — The Edit-Apply-Lint-Test Loop&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Aider&#39;s core loop is simpler than a full autonomous agent loop — it&#39;s a <strong>human-directed, single-turn edit cycle</strong> with optional automated lint/test feedback. The human remains in control of the conversation, but within each turn, aider can iterate autonomously on lint and test failures.</p><p>This is a key distinction from tools like Claude Code or Devin: aider doesn&#39;t plan multi-step strategies, browse documentation, or decide what to do next. The user tells it what to change, and aider focuses on producing correct edits.</p><h2 id="the-core-loop" tabindex="-1">The Core Loop <a class="header-anchor" href="#the-core-loop" aria-label="Permalink to &quot;The Core Loop&quot;">​</a></h2>',5)),(o(),s(l,null,{default:t(()=>[r(i,{id:"mermaid-15",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%22User%20Input%5Cn(e.g.%20'Add%20error%20handling%20to%20the%20%2Fsqrt%20endpoint')%22%5D%0A%20%20%20%20B%5B%221.%20Context%20Assembly%5Cnsystem%20prompt%20%C2%B7%20repo%20map%20%C2%B7%20added%20files%20%C2%B7%20chat%20history%20%C2%B7%20user%20message%22%5D%0A%20%20%20%20C%5B%222.%20LLM%20Inference%5Cnsend%20prompt%20%C2%B7%20stream%20response%20to%20terminal%5Cn(architect%20mode%3A%20two%20sequential%20LLM%20calls)%22%5D%0A%20%20%20%20D%5B%223.%20Parse%20Edits%5Cnextract%20file%20edits%20using%20edit%20format%20parser%5Cndiff%20%C2%B7%20whole%20%C2%B7%20udiff%20%C2%B7%20architect%22%5D%0A%20%20%20%20E%5B%224.%20Apply%20Edits%5Cnwrite%20changes%20to%20disk%5Cndiff%3A%20fuzzy%20search%2Freplace%20%C2%B7%20whole%3A%20replace%20entire%20file%22%5D%0A%20%20%20%20F%5B%225.%20Git%20Commit%5Cnauto-commit%20via%20weak%20model%5CnConventional%20Commits%20format%20%C2%B7%20(aider)%20attribution%22%5D%0A%20%20%20%20G%7B%226.%20Lint%5Cn(if%20--auto-lint)%22%7D%0A%20%20%20%20H%7B%227.%20Test%5Cn(if%20--auto-test)%22%7D%0A%20%20%20%20I%5B%22Ready%20for%20next%20user%20message%22%5D%0A%0A%20%20%20%20A%20--%3E%20B%20--%3E%20C%20--%3E%20D%20--%3E%20E%20--%3E%20F%20--%3E%20G%0A%20%20%20%20G%20--%3E%7Cerrors%20found%7C%20D%0A%20%20%20%20G%20--%3E%7Cclean%7C%20H%0A%20%20%20%20H%20--%3E%7Ctests%20fail%7C%20D%0A%20%20%20%20H%20--%3E%7Ctests%20pass%7C%20I%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[n(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=a('<h2 id="detailed-step-breakdown" tabindex="-1">Detailed Step Breakdown <a class="header-anchor" href="#detailed-step-breakdown" aria-label="Permalink to &quot;Detailed Step Breakdown&quot;">​</a></h2><h3 id="step-1-context-assembly" tabindex="-1">Step 1: Context Assembly <a class="header-anchor" href="#step-1-context-assembly" aria-label="Permalink to &quot;Step 1: Context Assembly&quot;">​</a></h3><p>The context assembly is where aider&#39;s intelligence lives. For each LLM call, it constructs a prompt containing:</p><ol><li><p><strong>System prompt</strong> — Instructions specific to the edit format (e.g., &quot;Return edits as SEARCH/REPLACE blocks&quot;). Each format has its own <code>*_prompts.py</code> file with carefully crafted instructions.</p></li><li><p><strong>Repo map</strong> — A ranked, token-budgeted summary of the codebase. The map dynamically expands when no files have been added to chat (to help the LLM understand the full repo) and contracts as files are added and conversation grows.</p></li><li><p><strong>Added files</strong> — Full content of files the user has <code>/add</code>&#39;d to the chat. These are the files the LLM is allowed to edit.</p></li><li><p><strong>Read-only files</strong> — Files added with <code>/read-only</code> that provide context but can&#39;t be edited.</p></li><li><p><strong>Chat history</strong> — Previous messages in the conversation. Aider manages this carefully — it summarizes old messages when the context grows too large.</p></li><li><p><strong>The user&#39;s message</strong> — The actual request.</p></li></ol><h3 id="step-2-llm-inference" tabindex="-1">Step 2: LLM Inference <a class="header-anchor" href="#step-2-llm-inference" aria-label="Permalink to &quot;Step 2: LLM Inference&quot;">​</a></h3><p>Aider streams the LLM response in real time, displaying it in the terminal with syntax highlighting. Key behaviors:</p><ul><li><strong>Streaming display</strong> — Code appears as it&#39;s generated, with live syntax highlighting</li><li><strong>Token counting</strong> — Tracks tokens used and remaining budget</li><li><strong>Retry logic</strong> — Handles rate limits and transient API errors with exponential backoff</li></ul><h3 id="step-3-parse-edits" tabindex="-1">Step 3: Parse Edits <a class="header-anchor" href="#step-3-parse-edits" aria-label="Permalink to &quot;Step 3: Parse Edits&quot;">​</a></h3><p>Each edit format has its own parser. The parsers must handle LLM imperfections:</p><ul><li><strong>Fuzzy matching</strong> for diff format — if the SEARCH block doesn&#39;t exactly match the file, aider tries fuzzy matching (stripping whitespace, ignoring blank lines, etc.)</li><li><strong>Multiple edit blocks</strong> — A single response can contain edits to multiple files</li><li><strong>New file creation</strong> — The LLM can create new files by specifying a path that doesn&#39;t exist</li></ul><h3 id="step-4-apply-edits" tabindex="-1">Step 4: Apply Edits <a class="header-anchor" href="#step-4-apply-edits" aria-label="Permalink to &quot;Step 4: Apply Edits&quot;">​</a></h3><p>For the <code>diff</code> (search/replace) format, application involves:</p><ol><li>Find the SEARCH text in the file</li><li>If exact match fails, try progressively fuzzier matching</li><li>Replace with the REPLACE text</li><li>Handle multiple edits to the same file in order</li></ol><p>For the <code>whole</code> format, the entire file is simply replaced.</p><h3 id="step-5-git-commit" tabindex="-1">Step 5: Git Commit <a class="header-anchor" href="#step-5-git-commit" aria-label="Permalink to &quot;Step 5: Git Commit&quot;">​</a></h3><p>The auto-commit is notable for its design:</p><ul><li>Uses the <strong>weak model</strong> (a cheaper, faster model) to generate commit messages</li><li>Sends the diff and chat context to the weak model</li><li>Follows Conventional Commits format by default</li><li>Commit message prompt is customizable</li><li>Dirty files are pre-committed to protect user work</li></ul><h3 id="steps-6-7-lint-and-test-feedback-loop" tabindex="-1">Steps 6-7: Lint and Test Feedback Loop <a class="header-anchor" href="#steps-6-7-lint-and-test-feedback-loop" aria-label="Permalink to &quot;Steps 6-7: Lint and Test Feedback Loop&quot;">​</a></h3><p>This is where aider becomes somewhat agentic — it can <strong>autonomously iterate</strong> on lint and test failures:</p><ol><li>Run linter/tests on modified files</li><li>If errors found, send error output back to the LLM</li><li>LLM produces new edits to fix the errors</li><li>Apply edits, commit, lint/test again</li><li>Repeat with bounded retries</li></ol><p>This is the same approach used in the benchmark: the LLM gets two attempts (initial + one fix attempt based on test output).</p><h2 id="architect-mode-the-two-model-loop" tabindex="-1">Architect Mode: The Two-Model Loop <a class="header-anchor" href="#architect-mode-the-two-model-loop" aria-label="Permalink to &quot;Architect Mode: The Two-Model Loop&quot;">​</a></h2><p>In architect mode, the loop expands:</p>',23)),(o(),s(l,null,{default:t(()=>[r(i,{id:"mermaid-209",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%22User%20Request%22%5D%0A%20%20%20%20B%5B%22Architect%20Model%5Cn(e.g.%20o3%2C%20DeepSeek%20R1)%5CnDescribes%20how%20to%20solve%20the%20problem%5CnReturns%3A%20plain%20text%20solution%20description%22%5D%0A%20%20%20%20C%5B%22Editor%20Model%5Cn(e.g.%20GPT-4.1%2C%20Sonnet)%5CnTurns%20solution%20into%20file%20edits%5CnReturns%3A%20structured%20edits%20in%20diff%2Fwhole%20format%22%5D%0A%20%20%20%20D%5B%22Apply%20%E2%86%92%20Commit%20%E2%86%92%20Lint%20%E2%86%92%20Test%22%5D%0A%0A%20%20%20%20A%20--%3E%20B%20--%3E%20C%20--%3E%20D%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[n(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=a('<p>This split allows:</p><ul><li><strong>Reasoning models</strong> (o1, o3, R1) to focus purely on problem-solving</li><li><strong>Code-editing models</strong> (Sonnet, GPT-4o) to focus on producing clean, parseable edits</li><li>Each model plays to its strengths</li></ul><h2 id="comparison-to-autonomous-agent-loops" tabindex="-1">Comparison to Autonomous Agent Loops <a class="header-anchor" href="#comparison-to-autonomous-agent-loops" aria-label="Permalink to &quot;Comparison to Autonomous Agent Loops&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>Aider</th><th>Autonomous Agents (Claude Code, etc.)</th></tr></thead><tbody><tr><td><strong>Who decides what to do?</strong></td><td>The human</td><td>The agent (with tool calls)</td></tr><tr><td><strong>Multi-step planning</strong></td><td>No — single-turn edits</td><td>Yes — plans and executes</td></tr><tr><td><strong>Tool use</strong></td><td>Edit files, run lint/test</td><td>Shell, browser, file ops, search</td></tr><tr><td><strong>Iteration</strong></td><td>On lint/test failures only</td><td>On any sub-goal failure</td></tr><tr><td><strong>Context management</strong></td><td>Manual (/add, /drop)</td><td>Automatic (agent decides)</td></tr><tr><td><strong>Strengths</strong></td><td>Predictable, fast, low cost</td><td>Handles complex tasks autonomously</td></tr><tr><td><strong>Weaknesses</strong></td><td>Requires human guidance</td><td>Expensive, sometimes unpredictable</td></tr></tbody></table><h2 id="the-benchmark-loop" tabindex="-1">The Benchmark Loop <a class="header-anchor" href="#the-benchmark-loop" aria-label="Permalink to &quot;The Benchmark Loop&quot;">​</a></h2><p>The benchmark (<code>benchmark/</code>) uses a simplified version of this loop:</p><ol><li>Send exercise instructions + stub file to LLM</li><li>Parse and apply edits</li><li>Run unit tests</li><li>If tests fail, send first 50 lines of error output + &quot;fix it&quot; message</li><li>Parse and apply second attempt</li><li>Run tests again → record pass/fail</li></ol><p>This two-attempt structure is the standard for the Aider leaderboard, and it&#39;s a fair approximation of real interactive use (initial attempt + one round of debugging).</p>',8))])}const w=d(c,[["render",m]]);export{T as __pageData,w as default};
